import Foundation

/// LinkLiar + Rust Integration using swift-bridge generated code.
///
/// This file provides convenient wrappers and extensions for using
/// the generated Rust types from Swift.
///
/// The generated files in this directory are created by swift-bridge-cli
/// and provide type-safe, memory-safe access to Rust functions.

// MARK: - Generated Swift Imports

// The following files are auto-generated by swift-bridge-cli:
// - SwiftBridgeCore.swift - Core FFI utilities
// - linktools/linktools.swift - Generated Swift bindings for our Rust types

// MARK: - LinkError Extension

extension LinkError: LocalizedError {
    public var errorDescription: String? {
        switch self {
        case .InvalidFormat:
            return "Invalid format"
        }
    }
}

// MARK: - MACAddress Convenience Extensions

extension MACAddress {
    /// Convert MACAddress to String
    public func toString() -> String {
        return to_string().toSwiftString()
    }

    /// Anonymize the MAC address (show only prefix)
    public func anonymize() -> String {
        return anonymize().toSwiftString()
    }

    /// Get OUI as Oui object
    public func toOui() -> Oui {
        return to_oui()
    }

    /// Lookup vendor name
    public func lookupVendor() -> String? {
        return lookup_vendor()?.toSwiftString()
    }
}

// MARK: - Oui Convenience Extensions

extension Oui {
    /// Convert Oui to String
    public func toString() -> String {
        return to_string().toSwiftString()
    }

    /// Convert Oui to hex string (without separators)
    public func toHexString() -> String {
        return to_hex_string().toSwiftString()
    }

    /// Lookup vendor name
    public func lookupVendor() -> String? {
        return lookup_vendor()?.toSwiftString()
    }
}

// MARK: - Bssid Convenience Extensions

extension Bssid {
    /// Convert Bssid to String
    public func toString() -> String {
        return to_string().toSwiftString()
    }

    /// Get as MACAddress
    public func toMac() -> MACAddress {
        return to_mac()
    }

    /// Check if this indicates a hidden SSID
    public func isHiddenSSID() -> Bool {
        return is_hidden_ssid_indicator()
    }
}

// MARK: - Ssid Convenience Extensions

extension Ssid {
    /// Convert Ssid to String
    public func toString() -> String {
        return to_string().toSwiftString()
    }

    /// Check if this is a hidden SSID
    public func isHidden() -> Bool {
        return is_hidden()
    }

    /// Check if this is a valid SSID
    public func isValid() -> Bool {
        return is_valid()
    }

    /// Check if this is a carrier WiFi network
    public func isCarrierWiFi() -> Bool {
        return is_carrier_wifi()
    }

    /// Check if this is a public hotspot
    public func isPublicHotspot() -> Bool {
        return is_public_hotspot()
    }
}

// MARK: - RustString Helper

extension RustString {
    /// Convert RustString to Swift String
    public func toSwiftString() -> String {
        let len = __swift_bridge__$RustString_len(ptr)
        let bytes = __swift_bridge__$RustString_bytes(ptr)
        defer {
            __swift_bridge__$RustString_free(ptr)
        }

        return String(decoding: UnsafeBufferPointer(start: bytes, count: Int(len)), as: UTF8.self)
    }
}

// MARK: - Convenience Functions

/// Rust integration helper functions
enum RustIntegration {

    /// Parse a MAC address using Rust library
    static func parseMAC(_ address: String) throws -> MACAddress {
        return try MACAddress(address)
    }

    /// Generate a random local MAC address using Rust library
    static func randomLocalMAC() -> MACAddress {
        return mac_random_local()
    }

    /// Generate a random MAC for a specific vendor
    static func randomMACForVendor(_ vendorId: String) -> MACAddress? {
        return mac_random_with_vendor(vendorId)
    }

    /// Parse BSSID
    static func parseBSSID(_ address: String) throws -> Bssid {
        return try Bssid(address)
    }

    /// Parse SSID
    static func parseSSID(_ name: String) throws -> Ssid {
        return try Ssid(name)
    }

    /// Lookup vendor by OUI string
    static func lookupVendor(oui: String) -> String? {
        do {
            let ouiObj = try Oui(oui)
            return ouiObj.lookupVendor()
        } catch {
            return nil
        }
    }
}

// MARK: - Batch Operations

/// Batch operations for MAC addresses using Rust
enum RustBatch {

    /// Validate multiple MAC addresses
    static func validateMACs(_ addresses: [String]) -> [Bool] {
        return batch_validate_macs(addrs: addresses)
    }

    /// Normalize multiple MAC addresses to colon format
    static func normalizeMACs(_ addresses: [String]) -> [String] {
        let rustStrings = batch_normalize_macs(addrs: addresses)
        return rustStrings.map { $0.toSwiftString() }
    }

    /// Anonymize multiple MAC addresses
    static func anonymizeMACs(_ addresses: [String]) -> [String] {
        let rustStrings = batch_anonymize_macs(addrs: addresses)
        return rustStrings.map { $0.toSwiftString() }
    }

    /// Generate multiple random local MAC addresses
    static func generateLocalMACs(count: Int) -> [String] {
        let rustStrings = batch_generate_local_macs(count: UInt(count))
        return rustStrings.map { $0.toSwiftString() }
    }

    /// Generate multiple random MAC addresses for a vendor
    static func generateVendorMACs(_ vendorId: String, count: Int) -> [String] {
        let rustStrings = batch_generate_vendor_macs(vendorId, count: UInt(count))
        return rustStrings.map { $0.toSwiftString() }
    }
}

// MARK: - Similarity Operations

/// MAC similarity operations using Rust
enum RustSimilarity {

    /// Calculate similarity score between two MAC addresses (0.0 - 1.0)
    static func similarityScore(_ mac1: String, _ mac2: String) -> Double? {
        return mac_similarity_score(mac1, mac2)
    }

    /// Check if two MAC addresses are from the same vendor
    static func areSameVendor(_ mac1: String, _ mac2: String) -> Bool {
        return mac_are_same_vendor(mac1, mac2)
    }
}

// MARK: - Usage Examples

#if DEBUG

enum RustIntegrationExample {

    /// Example 1: Parse a MAC address
    static func exampleParseMAC() {
        do {
            let mac = try RustIntegration.parseMAC("00:03:93:12:34:56")
            print("Parsed MAC: \(mac.toString())")
        } catch {
            print("Error parsing MAC: \(error.localizedDescription)")
        }
    }

    /// Example 2: Generate random MAC
    static func exampleRandomMAC() {
        let mac = RustIntegration.randomLocalMAC()
        print("Random MAC: \(mac.toString())")
    }

    /// Example 3: Anonymize MAC
    static func exampleAnonymize() {
        do {
            let mac = try RustIntegration.parseMAC("00:03:93:12:34:56")
            let anonymized = mac.anonymize()
            print("Anonymized: \(anonymized)")
        } catch {
            print("Error: \(error.localizedDescription)")
        }
    }

    /// Example 4: Get OUI from MAC
    static func exampleGetOUI() {
        do {
            let mac = try RustIntegration.parseMAC("00:03:93:12:34:56")
            let oui = mac.toOui()
            print("OUI: \(oui.toString())")

            if let vendor = oui.lookupVendor() {
                print("Vendor: \(vendor)")
            }
        } catch {
            print("Error: \(error.localizedDescription)")
        }
    }

    /// Example 5: Lookup vendor
    static func exampleLookupVendor() {
        do {
            let mac = try RustIntegration.parseMAC("00:03:93:12:34:56")
            if let vendor = mac.lookupVendor() {
                print("Vendor: \(vendor)")
            }
        } catch {
            print("Error: \(error.localizedDescription)")
        }
    }

    /// Example 6: Parse OUI
    static func exampleParseOUI() {
        do {
            let oui = try Oui("00:03:93")
            print("OUI: \(oui.toString())")
            print("OUI (hex): \(oui.toHexString())")
        } catch {
            print("Error parsing OUI: \(error.localizedDescription)")
        }
    }

    /// Example 7: Random MAC for vendor
    static func exampleRandomMACForVendor() {
        if let mac = RustIntegration.randomMACForVendor("apple") {
            print("Random Apple MAC: \(mac.toString())")
        }
    }

    /// Example 8: Parse BSSID
    static func exampleParseBSSID() {
        do {
            let bssid = try RustIntegration.parseBSSID("AA:BB:CC:DD:EE:FF")
            print("BSSID: \(bssid.toString())")
            print("Hidden SSID: \(bssid.isHiddenSSID())")
        } catch {
            print("Error: \(error.localizedDescription)")
        }
    }

    /// Example 9: Parse SSID
    static func exampleParseSSID() {
        do {
            let ssid = try RustIntegration.parseSSID("MyNetwork")
            print("SSID: \(ssid.toString())")
            print("Is hidden: \(ssid.isHidden())")
            print("Is carrier WiFi: \(ssid.isCarrierWiFi())")
        } catch {
            print("Error: \(error.localizedDescription)")
        }
    }

    /// Example 10: Batch operations
    static func exampleBatchOperations() {
        let addresses = ["AA:BB:CC:DD:EE:FF", "invalid", "11:22:33:44:55:66"]
        let valid = RustBatch.validateMACs(addresses)
        print("Valid addresses: \(valid)")

        let normalized = RustBatch.normalizeMACs(["aabbccddeeff", "11-22-33-44-55-66"])
        print("Normalized: \(normalized)")

        let randomMacs = RustBatch.generateLocalMACs(count: 5)
        print("Random MACs: \(randomMacs)")
    }

    /// Example 11: Similarity
    static func exampleSimilarity() {
        let score = RustSimilarity.similarityScore("AA:BB:CC:DD:EE:FF", "AA:BB:CC:11:22:33")
        print("Similarity score: \(String(describing: score))")

        let sameVendor = RustSimilarity.areSameVendor("AA:BB:CC:DD:EE:FF", "AA:BB:CC:11:22:33")
        print("Same vendor: \(sameVendor)")
    }

    /// Run all examples
    static func runAllExamples() {
        print("=== Rust Integration Examples ===")
        exampleParseMAC()
        exampleRandomMAC()
        exampleAnonymize()
        exampleGetOUI()
        exampleLookupVendor()
        exampleParseOUI()
        exampleRandomMACForVendor()
        exampleParseBSSID()
        exampleParseSSID()
        exampleBatchOperations()
        exampleSimilarity()
        print("=== End Examples ===")
    }
}

#endif
